    13→async function getSourceWithUrls(id: number) {
    14→  const [source] = await db.select().from(sourcesTable).where(eq(sourcesTable.id, id)).limit(1);
    15→  if (!source) return null;
    16→  const urls = await db.select().from(sourceUrlsTable).where(eq(sourceUrlsTable.sourceId, id));
    17→  return { ...source, urls };
    18→}
    19→
    20→router.get("/sources", async (_req, res) => {
    21→  const sources = await db.select().from(sourcesTable).orderBy(sourcesTable.name);
    22→  const result = await Promise.all(sources.map(async (s) => {
    23→    const urls = await db.select().from(sourceUrlsTable).where(eq(sourceUrlsTable.sourceId, s.id));
    24→    return { ...s, urls };
    25→  }));
    26→  res.json(result);
    27→});
    28→
    29→router.get("/sources/:id", async (req, res) => {
    30→  const source = await getSourceWithUrls(parseInt(req.params.id));
    31→  if (!source) return res.status(404).json({ error: "Fonte non trovata" });
    32→  res.json(source);
    33→});
    34→
    35→router.post("/sources", async (req, res) => {
    36→  const { name, browseractWorkflowId, promptOverride, active = true, preferredScraper = "browseract", urls = [] } = req.body;
    37→  if (!name) return res.status(400).json({ error: "Nome richiesto" });
    38→  if (!urls.length) return res.status(400).json({ error: "Almeno un URL richiesto" });
    39→
    40→  const [source] = await db.insert(sourcesTable).values({
    41→    name, browseractWorkflowId, promptOverride, active, preferredScraper
    42→  }).returning();
    43→
    44→  for (const url of urls) {
    45→    await db.insert(sourceUrlsTable).values({
    46→      sourceId: source.id, url: url.url, label: url.label || null,
    47→      browseractWorkflowId: url.browseractWorkflowId || null, active: url.active ?? true,
    48→    });
    49→  }
    50→
    51→  const result = await getSourceWithUrls(source.id);
    52→  res.status(201).json(result);
    53→});
    54→
    55→router.put("/sources/:id", async (req, res) => {
    56→  const id = parseInt(req.params.id);
    57→  const { name, browseractWorkflowId, promptOverride, active, preferredScraper, urls } = req.body;
    58→
    59→  await db.update(sourcesTable).set({
    60→    name, browseractWorkflowId, promptOverride, active, preferredScraper
    61→  }).where(eq(sourcesTable.id, id));
    62→
    63→  if (urls) {
    64→    const existingUrls = await db.select().from(sourceUrlsTable).where(eq(sourceUrlsTable.sourceId, id));
    65→    const existingIds = existingUrls.map(u => u.id);
    66→    const incomingIds = urls.filter((u: { id?: number }) => u.id).map((u: { id: number }) => u.id);
    67→    const toDelete = existingIds.filter(id => !incomingIds.includes(id));
    68→    if (toDelete.length) await db.delete(sourceUrlsTable).where(inArray(sourceUrlsTable.id, toDelete));
    69→
    70→    for (const url of urls) {
    71→      if (url.id) {
    72→        await db.update(sourceUrlsTable).set({
    73→          url: url.url, label: url.label || null,
    74→          browseractWorkflowId: url.browseractWorkflowId || null, active: url.active ?? true,
    75→        }).where(eq(sourceUrlsTable.id, url.id));
    76→      } else {
    77→        await db.insert(sourceUrlsTable).values({
    78→          sourceId: id, url: url.url, label: url.label || null,
    79→          browseractWorkflowId: url.browseractWorkflowId || null, active: url.active ?? true,
    80→        });
    81→      }
    82→    }
    83→  }
    84→
    85→  const result = await getSourceWithUrls(id);
    86→  res.json(result);
    87→});
    88→
    89→router.delete("/sources/:id", async (req, res) => {
    90→  const id = parseInt(req.params.id);
    91→  await db.delete(sourcesTable).where(eq(sourcesTable.id, id));
    92→  res.json({ message: "Fonte eliminata" });
    93→});
